import{_ as s,o as a,c as i,ag as t}from"./chunks/framework.BBkp40gP.js";const k=JSON.parse('{"title":"Getting Started with KubeJS","description":"","frontmatter":{},"headers":[],"relativePath":"recipes/getting-started.md","filePath":"recipes/getting-started.md"}'),n={name:"recipes/getting-started.md"};function r(l,e,p,h,o,c){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="getting-started-with-kubejs" tabindex="-1">Getting Started with KubeJS <a class="header-anchor" href="#getting-started-with-kubejs" aria-label="Permalink to &quot;Getting Started with KubeJS&quot;">​</a></h1><p>Nostalgic Trees integrates cleanly with <a href="https://www.curseforge.com/minecraft/mc-mods/kubejs" target="_blank" rel="noreferrer">KubeJS</a>. This page covers the basics: where scripts go, how to load them, and the minimal pattern that every recipe script follows.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Install <a href="https://www.curseforge.com/minecraft/mc-mods/kubejs" target="_blank" rel="noreferrer">KubeJS for NeoForge 1.21.1</a> (version 2101.7.2 or later). Launch once — it creates a <code>kubejs/</code> folder in your instance.</p><h2 id="folder-structure" tabindex="-1">Folder structure <a class="header-anchor" href="#folder-structure" aria-label="Permalink to &quot;Folder structure&quot;">​</a></h2><p>All recipe modification goes in <code>kubejs/server_scripts/</code>. Files must end in <code>.js</code>. To disable a script without deleting it, rename it to <code>.js.off</code> (or any extension other than <code>.js</code>).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kubejs/</span></span>
<span class="line"><span>├── server_scripts/      ← all recipe scripts go here</span></span>
<span class="line"><span>├── client_scripts/      ← JEI hiding etc. (not covered in most of this wiki)</span></span>
<span class="line"><span>├── startup_scripts/     ← custom creative tabs etc. (advanced)</span></span>
<span class="line"><span>└── exported/            ← registry dumps (useful for debugging)</span></span></code></pre></div><h2 id="the-minimal-pattern" tabindex="-1">The minimal pattern <a class="header-anchor" href="#the-minimal-pattern" aria-label="Permalink to &quot;The minimal pattern&quot;">​</a></h2><p>Every recipe script looks like this:</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ServerEvents.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">recipes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">event</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // your code here</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><p><code>ServerEvents.recipes</code> fires once during world load. Inside the callback, <code>event</code> is the handle you use to add, remove, and modify recipes. Everything else is layered on top of this pattern.</p><h2 id="reloading-scripts" tabindex="-1">Reloading scripts <a class="header-anchor" href="#reloading-scripts" aria-label="Permalink to &quot;Reloading scripts&quot;">​</a></h2><p>After editing a server script, you have two options:</p><ul><li><strong>In-game:</strong> <code>/reload</code> — re-runs server scripts against the current world. Fast.</li><li><strong>Restart the world.</strong> Reliable fallback if <code>/reload</code> misses anything.</li></ul><p>Startup scripts (items, tabs, etc.) require a full game restart — they run once at launch.</p><h2 id="your-first-script" tabindex="-1">Your first script <a class="header-anchor" href="#your-first-script" aria-label="Permalink to &quot;Your first script&quot;">​</a></h2><p>Save this as <code>kubejs/server_scripts/test.js</code>:</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ServerEvents.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">recipes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">event</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    event.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shaped</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &#39;minecraft:diamond&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">            &#39; D &#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">            &#39;DDD&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">            &#39; D &#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        ],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            D: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;minecraft:dirt&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;kubejs:test_diamond_from_dirt&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><p><code>/reload</code> in-game, open JEI, search for &quot;diamond&quot; — you should see a new recipe that makes a diamond from 5 dirt. Delete the script or rename to <code>.js.off</code>, <code>/reload</code> again, recipe is gone.</p><p>If the recipe doesn&#39;t appear, check <code>kubejs/logs/startup.log</code> for errors. Syntax mistakes fail silently in-game and only show up in that log.</p><h2 id="what-to-read-next" tabindex="-1">What to read next <a class="header-anchor" href="#what-to-read-next" aria-label="Permalink to &quot;What to read next&quot;">​</a></h2><ul><li><a href="/wiki/recipes/resource">Resource Crafts</a> — rebalance the per-tree output recipes</li><li><a href="/wiki/recipes/mutation">Mutations</a> — add or remove sapling mutation paths</li><li><a href="/wiki/reference/targeting">Targeting Recipes</a> — the full filter system for <code>event.remove</code></li></ul><h2 id="learning-kubejs-itself" tabindex="-1">Learning KubeJS itself <a class="header-anchor" href="#learning-kubejs-itself" aria-label="Permalink to &quot;Learning KubeJS itself&quot;">​</a></h2><p>This wiki covers Nostalgic Trees integration specifically. For general KubeJS documentation, see <a href="https://kubejs.com" target="_blank" rel="noreferrer">kubejs.com</a> — their wiki covers items, tags, events, and scripting patterns that aren&#39;t NT-specific.</p>`,24)])])}const g=s(n,[["render",r]]);export{k as __pageData,g as default};
